questionvariables.text:
/* ===== Randomised parameters ===== */
N_val:  rand([100, 200, 500]);
I_val:  rand([1, 2, 5]);
l1_val: rand([0.2, 0.3, 0.4]);
l2_val: rand([5e-4, 1e-3, 2e-3]);
Ac_val: rand([4e-4, 9e-4, 16e-4]);
mur_val: rand([500, 1000, 2000]);
mu0: 4*%pi*1e-7;

/* ===== Derived answers ===== */
/* From Ampere: NI = H_core*l1 + H_gap*l2                        */
/* Flux continuity: B = mur*mu0*H_core = mu0*H_gap                */
/* -> NI = B*l1/(mur*mu0) + B*l2/mu0 = B*(l1/(mur*mu0)+l2/mu0)  */
/* -> B = N*I*mu0 / (l1/mur + l2)                                 */

ta_B_sym: N_val*I_val*mu0 / (l1_val/mur_val + l2_val);
ta_B:     float(ta_B_sym);

ta_Hcore_sym: ta_B_sym/(mur_val*mu0);
ta_Hcore: float(ta_Hcore_sym);

ta_Hgap: float(ta_B/(mu0));

ta_phi:   float(ta_B * Ac_val);

/* ===== Teacher answers ===== */
ta_law:    2;
ta_design: 2;

ta1: ta_law;
ta2: ta_B_sym;
ta3: ta_B;
ta4: ta_Hcore;
ta5: ta_phi;
/* ta6 is essay/notes — always pass */
ta6: "Gauss law for magnetism requires flux continuity.";
ta7: ta_design;
